57→export const MAIN_LABEL = '[MAIN]';
58→
59→/** 從 agentId 建立標籤（例如 '[abc1234]'） */
60→export function makeAgentLabel(agentId: string): string {
61→  return `[${agentId}]`;
62→}
63→
64→/** 從標籤提取 agentId（例如 '[abc1234]' -> 'abc1234'） */
65→export function extractAgentIdFromLabel(label: string): string {
66→  return label.slice(1, -1);
67→}
