  1→import type {
  2→  PaneInfo,
  3→  TerminalController,
  4→} from './terminal-controller.interface.ts';
  5→
  6→/** MVP 最大 pane 數量（安全上限，Phase 2 可設定） */
  7→const MAX_PANES = 6;
  8→
  9→/** Pane title description 最大長度 */
 10→const MAX_DESCRIPTION_LENGTH = 50;
 11→
 12→/**
 13→ * 清理並格式化 pane title
 14→ * - 移除 control characters 和 tmux # 特殊序列
 15→ * - 截斷超長描述
 16→ * - 格式: "agentId: description"
 17→ */
 18→function sanitizePaneTitle(agentId: string, description: string): string {
 19→  const sanitized = description
 20→    // eslint-disable-next-line no-control-regex
 21→    .replace(/[\x00-\x1f\x7f]/g, ' ') // control chars -> space
 22→    .replace(/#/g, '') // tmux interprets #() sequences
 23→    .trim()
 24→    .slice(0, MAX_DESCRIPTION_LENGTH);
 25→
 26→  return `${agentId}: ${sanitized}`;
 27→}
 28→
 29→/** applyLayout debounce 延遲（ms） */
 30→const LAYOUT_DEBOUNCE_MS = 50;
 31→
 32→/**
 33→ * Pane 生命週期管理器
 34→ *
 35→ * 負責追蹤所有開啟的 pane，並在需要時統一清理。
 36→ * 是 pane 狀態的唯一 source of truth。
 37→ */
 38→export class PaneManager {
 39→  private controller: TerminalController;
 40→  private commandBuilder: (agentId: string, subagentPath: string) => string;
 41→  private panes: Map<string, PaneInfo> = new Map(); // agentId -> PaneInfo
 42→  /** 正在開啟中的 agentId（防止併發超開） */
 43→  private pendingAgentIds: Set<string> = new Set();
 44→  /** 待關閉的 agentId（pane 還在 pending 時就收到 done 事件） */
 45→  private pendingCloseAgentIds: Set<string> = new Set();
 46→  /** applyLayout debounce timer */
 47→  private layoutTimer: ReturnType<typeof setTimeout> | null = null;
 48→
 49→  constructor(
 50→    controller: TerminalController,
 51→    commandBuilder: (agentId: string, subagentPath: string) => string
 52→  ) {
 53→    this.controller = controller;
 54→    this.commandBuilder = commandBuilder;
 55→  }
 56→
 57→  /**
 58→   * 為 subagent 開啟新 pane
 59→   * - 已存在相同 agentId 的 pane 時跳過（去重）
 60→   * - 超過 MAX_PANES 時跳過（安全上限）
 61→   * - 使用 pendingAgentIds 防止併發呼叫超開
 62→   * - description 用於命名 pane（可選，來自 Task tool_use 的 description 欄位）
 63→   */
 64→  async openPane(
 65→    agentId: string,
 66→    subagentPath: string,
 67→    description?: string
 68→  ): Promise<void> {
 69→    if (this.panes.has(agentId)) return;
 70→    if (this.pendingAgentIds.has(agentId)) return;
 71→    if (this.panes.size + this.pendingAgentIds.size >= MAX_PANES) return;
 72→
 73→    this.pendingAgentIds.add(agentId);
 74→    try {
 75→      const cmd = this.commandBuilder(agentId, subagentPath);
 76→      const pane = await this.controller.createPane(cmd, agentId);
 77→      if (pane) {
 78→        this.panes.set(agentId, pane);
 79→
 80→        // Best-effort pane naming (before pendingClose check)
 81→        if (description && this.controller.renamePane) {
 82→          const title = sanitizePaneTitle(agentId, description);
 83→          try {
 84→            await this.controller.renamePane(pane.id, title);
 85→          } catch {
 86→            // 命名失敗不影響 pane 功能
 87→          }
 88→        }
 89→
 90→        // 排程佈局更新（debounce，連續開多個 pane 時只觸發一次）
 91→        this.scheduleLayout();
 92→
 93→        // 檢查是否在 pending 期間收到了 done 事件
 94→        if (this.pendingCloseAgentIds.has(agentId)) {
 95→          this.pendingCloseAgentIds.delete(agentId);
 96→          // 立刻關閉這個 pane
 97→          await this.closePaneByAgentId(agentId);
 98→        }
 99→      } else {
100→        // createPane 失敗，清除待關閉狀態（沒有 pane 就不需要關閉）
101→        this.pendingCloseAgentIds.delete(agentId);
102→      }
103→    } catch {
104→      // 非預期錯誤（如 commandBuilder throw），清理所有相關狀態
105→      this.pendingCloseAgentIds.delete(agentId);
106→    } finally {
107→      this.pendingAgentIds.delete(agentId);
108→    }
109→  }
110→
111→  /**
112→   * 關閉所有已追蹤的 pane（best-effort）
113→   */
114→  async closeAll(): Promise<void> {
115→    this.clearLayoutTimer();
116→    const closePromises = [...this.panes.values()].map((p) =>
117→      this.controller.closePane(p.id).catch(() => {})
118→    );
119→    await Promise.all(closePromises);
120→    this.panes.clear();
121→    this.pendingCloseAgentIds.clear();
122→  }
123→
124→  /**
125→   * 排程佈局更新（debounce）
126→   * 連續開多個 pane 時只在最後觸發一次 tmux select-layout
127→   */
128→  private scheduleLayout(): void {
129→    this.clearLayoutTimer();
130→    this.layoutTimer = setTimeout(() => {
131→      this.layoutTimer = null;
132→      this.applyLayout().catch(() => {});
133→    }, LAYOUT_DEBOUNCE_MS);
134→  }
135→
136→  private clearLayoutTimer(): void {
137→    if (this.layoutTimer) {
138→      clearTimeout(this.layoutTimer);
139→      this.layoutTimer = null;
140→    }
141→  }
142→
143→  /**
144→   * 套用佈局（如果 controller 支援）
145→   * Best-effort 操作，失敗不影響核心功能
146→   */
147→  private async applyLayout(): Promise<void> {
148→    if (this.controller.applyLayout) {
149→      try {
150→        await this.controller.applyLayout('main-vertical');
151→      } catch {
152→        // 靜默忽略佈局失敗
153→      }
154→    }
155→  }
156→
157→  /**
158→   * 根據 agentId 關閉對應的 pane
159→   * Best-effort 操作，失敗不影響核心功能
160→   * 如果 pane 還在 pending，會標記為待關閉，等 pane 建立後自動關閉
161→   */
162→  async closePaneByAgentId(agentId: string): Promise<void> {
163→    // 如果 pane 還在開啟中，標記為待關閉
164→    if (this.pendingAgentIds.has(agentId) && !this.panes.has(agentId)) {
165→      this.pendingCloseAgentIds.add(agentId);
166→      return;
167→    }
168→
169→    const pane = this.panes.get(agentId);
170→    if (!pane) return;
171→
172→    // 立刻移除，防止並行呼叫重複觸發 closePane
173→    this.panes.delete(agentId);
174→
175→    try {
176→      await this.controller.closePane(pane.id);
177→    } catch {
178→      // 靜默忽略關閉失敗（pane 可能已經關閉）
179→    }
180→  }
181→
182→  /**
183→   * 目前開啟的 pane 數量
184→   */
185→  get activePaneCount(): number {
186→    return this.panes.size;
187→  }
188→
189→  /**
190→   * 檢查指定 agentId 是否有對應的 pane（包含 pending 狀態）
191→   * 用於判斷是否需要觸發 onSubagentDone
192→   */
193→  hasPaneForAgent(agentId: string): boolean {
194→    return this.panes.has(agentId) || this.pendingAgentIds.has(agentId);
195→  }
196→}
