  1→import { join } from 'node:path';
  2→import { Glob } from 'bun';
  3→import {
  4→  makeAgentLabel,
  5→  type OutputHandler,
  6→  type WatcherHandler,
  7→} from '../core/detector-interfaces.ts';
  8→
  9→// ============================================================
 10→// UUID Validation
 11→// ============================================================
 12→
 13→const UUID_REGEX =
 14→  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
 15→
 16→export function isValidCodexAgentId(id: string): boolean {
 17→  return UUID_REGEX.test(id);
 18→}
 19→
 20→/**
 21→ * 取 UUID 的高位時間戳段 + node 段前 4 碼作為短 label
 22→ * 例如 '019cc375-8a57'（避免 UUID v7 前兩段均為 timestamp 導致碰撞）
 23→ */
 24→export function makeCodexAgentLabel(agentId: string): string {
 25→  const parts = agentId.split('-');
 26→  // parts[4] 為 node/random 段，提供唯一性；parts[0] 為可讀時間戳
 27→  const shortId = `${parts[0]}-${(parts[4] ?? '').slice(0, 4)}`;
 28→  return makeAgentLabel(shortId);
 29→}
