 31→// ============================================================
 32→// Config & Types
 33→// ============================================================
 34→
 35→export interface CodexSubagentDetectorConfig {
 36→  /** dirname(mainSessionPath) — 日期目錄 */
 37→  sessionDateDir: string;
 38→  output: OutputHandler;
 39→  watcher: WatcherHandler;
 40→  /** options.follow && options.withSubagents */
 41→  enabled: boolean;
 42→  onNewSubagent?: (agentId: string, path: string, description?: string) => void;
 43→  /** 觸發條件：resume_agent / send_input 且 agentId 已知 */
 44→  onSubagentEnter?: (agentId: string, path: string) => void;
 45→  onSubagentDone?: (agentId: string) => void;
 46→}
 47→
 48→interface PendingSpawn {
 49→  agentType: string;
 50→  message: string;
 51→  timer: ReturnType<typeof setTimeout>;
 52→}
 53→
 54→// ============================================================
 55→// File finder with retry
 56→// ============================================================
 57→
 58→async function findSubagentFile(
 59→  dateDir: string,
 60→  agentId: string
 61→): Promise<string | null> {
 62→  const glob = new Glob(`rollout-*-${agentId}.jsonl`);
 63→  for (let i = 0; i < 30; i++) {
 64→    for await (const file of glob.scan(dateDir)) {
 65→      return join(dateDir, file);
 66→    }
 67→    if (i < 29) await new Promise((r) => setTimeout(r, 300));
 68→  }
 69→  return null;
 70→}
 71→
 72→// ============================================================
 73→// CodexSubagentDetector
 74→// ============================================================
 75→
 76→export class CodexSubagentDetector {
 77→  private pendingSpawns: Map<string, PendingSpawn> = new Map();
 78→  private registeredAgentPaths: Map<string, string> = new Map();
 79→  private config: CodexSubagentDetectorConfig;
 80→  private stopped = false;
 81→
 82→  constructor(
 83→    _existingAgentIds: string[],
 84→    config: CodexSubagentDetectorConfig
 85→  ) {
 86→    this.config = config;
 87→    // existingAgentIds reserved for future deduplication use
 88→  }
 89→
 90→  /**
 91→   * 預先登錄已存在的 subagent（供 handleSubagentResume 查詢）
 92→   */
 93→  registerExistingAgent(agentId: string, path: string): void {
 94→    this.registeredAgentPaths.set(agentId, path);
 95→  }
 96→
 97→  handleSpawnAgent(callId: string, agentType: string, message: string): void {
 98→    if (!this.config.enabled) return;
 99→
100→    // 防止同一 callId 重複登錄導致舊 timer 洩漏
101→    const existing = this.pendingSpawns.get(callId);
102→    if (existing) clearTimeout(existing.timer);
103→
104→    const timer = setTimeout(() => {
105→      this.pendingSpawns.delete(callId);
106→    }, 60000);
107→
108→    this.pendingSpawns.set(callId, { agentType, message, timer });
109→  }
110→
111→  handleSpawnAgentOutput(
112→    callId: string,
113→    output: { agent_id: string; nickname?: string }
114→  ): void {
115→    if (!this.config.enabled) return;
116→
117→    const pending = this.pendingSpawns.get(callId);
118→    if (!pending) {
119→      this.config.output.debug(`Codex: unknown callId ${callId}, ignoring`);
120→      return;
121→    }
122→
123→    const agentId = output.agent_id;
124→    if (!isValidCodexAgentId(agentId)) {
125→      this.config.output.warn(
126→        `Codex: invalid agent_id format (not UUID): ${agentId}`
127→      );
128→      return;
129→    }
130→
131→    // Skip already-registered agents (pre-filled at startup via registerExistingAgent)
132→    if (this.registeredAgentPaths.has(agentId)) {
133→      clearTimeout(pending.timer);
134→      this.pendingSpawns.delete(callId);
135→      return;
136→    }
137→
138→    // Fire async, but don't await in sync handler
139→    this._resolveSubagent(callId, pending, agentId).catch((err) => {
140→      this.config.output.error(
141→        `Codex: Failed to resolve subagent ${agentId} - ${err instanceof Error ? err.message : String(err)}`
142→      );
143→    });
144→  }
145→
146→  private async _resolveSubagent(
147→    callId: string,
148→    pending: PendingSpawn,
149→    agentId: string
150→  ): Promise<void> {
151→    const foundPath = await findSubagentFile(
152→      this.config.sessionDateDir,
153→      agentId
154→    );
155→
156→    // Guard：stop() 後捨棄結果，避免向舊 watcher 注入資料
157→    if (this.stopped) return;
158→
159→    if (!foundPath) {
160→      this.config.output.warn(
161→        `Codex subagent file not found after retries: ${agentId}`
162→      );
163→      return;
164→    }
165→
166→    // Cleanup pending
167→    clearTimeout(pending.timer);
168→    this.pendingSpawns.delete(callId);
169→
170→    // 記錄已知 agent（供 handleSubagentResume 查詢路徑）
171→    this.registeredAgentPaths.set(agentId, foundPath);
172→
173→    // Guard：addFile 前再次確認未停止（watcher 是 let 閉包，可能已換新實例）
174→    if (this.stopped) return;
175→
176→    const label = makeCodexAgentLabel(agentId);
177→    await this.config.watcher.addFile({ path: foundPath, label });
178→
179→    // Guard：addFile 是 async，完成後再確認一次，防止 onNewSubagent 對已切換的 session 觸發
180→    if (this.stopped) return;
181→
182→    const description =
183→      pending.agentType && pending.message
184→        ? `${pending.agentType}: ${pending.message.slice(0, 50)}`
185→        : undefined;
186→    this.config.onNewSubagent?.(agentId, foundPath, description);
187→  }
188→
189→  handleSubagentResume(agentId: string): void {
190→    if (!this.config.enabled) return;
191→    if (!isValidCodexAgentId(agentId)) return;
192→
193→    const path = this.registeredAgentPaths.get(agentId);
194→    if (path) {
195→      this.config.onSubagentEnter?.(agentId, path);
196→    }
197→  }
198→
199→  getAgentPath(agentId: string): string | undefined {
200→    return this.registeredAgentPaths.get(agentId);
201→  }
202→
203→  handleSubagentDone(agentId: string): void {
204→    this.config.onSubagentDone?.(agentId);
205→  }
206→
207→  stop(): void {
208→    this.stopped = true;
209→    for (const pending of this.pendingSpawns.values()) {
210→      clearTimeout(pending.timer);
211→    }
212→    this.pendingSpawns.clear();
213→    this.registeredAgentPaths.clear();
214→  }
215→}
